// SVG 与 hover DOM 全落 shadow 容器,无 document.head CSS
import { Fretboard } from 'https://cdn.jsdelivr.net/npm/@moonwave99/fretboard.js@0/+esm';
const el = document.createElement('div'); el.style.height = '260px'; shadowRoot.appendChild(el);
const fb = new Fretboard({ el, height: 260, width: el.clientWidth || 800, tuning: data.tuning, fretCount: data.fretCount });
if (data.view === 'scale') fb.renderScale(data.scale); else if (data.view === 'chord') fb.renderChord(data.chord); else fb.setDots(data.dots || []).render();
